#!/usr/bin/env Rscript

## aNCA clinical PK support task: PKNCA_impute_method_start_c1

suppressPackageStartupMessages({
  library(PKNCA)
})

## Helper to read TSV preserving header
read_tsv <- function(path) {
  read.table(path, header = TRUE, sep = "\t", stringsAsFactors = FALSE, check.names = FALSE)
}

## Helper: coerce 1-row tables to scalar vector (named)
scalar_or_vector <- function(df) {
  if (nrow(df) == 1L && ncol(df) == 1L) {
    return(df[[1]][1])
  }
  if (ncol(df) == 1L) {
    return(df[[1]])
  }
  df
}

## Read inputs
conc_df    <- read_tsv("inputs/conc.tsv")
end_df     <- read_tsv("inputs/end.tsv")
options_df <- read_tsv("inputs/options.tsv")
start_df   <- read_tsv("inputs/start.tsv")
time_df    <- read_tsv("inputs/time.tsv")

## Convert according to instructions
conc_arg    <- scalar_or_vector(conc_df)
end_arg     <- scalar_or_vector(end_df)
options_arg <- scalar_or_vector(options_df)
start_arg   <- scalar_or_vector(start_df)
time_arg    <- scalar_or_vector(time_df)

## Call target routine when arguments are acceptable
result_obj <- PKNCA_impute_method_start_c1(
  conc    = conc_arg,
  end     = end_arg,
  options = options_arg,
  start   = start_arg,
  time    = time_arg
)

## Normalize result for grading
# Make a compact, inspectable data.frame representation
normalize_result <- function(x) {
  if (is.data.frame(x)) {
    return(x)
  } else if (is.list(x)) {
    # Try to turn named list into data.frame
    nms <- names(x)
    if (!is.null(nms) && length(unique(nms)) == length(nms)) {
      df <- as.data.frame(x, check.names = FALSE, stringsAsFactors = FALSE)
      return(df)
    } else {
      return(data.frame(value = I(list(x))))
    }
  } else if (length(x) > 1L) {
    return(data.frame(value = x))
  } else {
    return(data.frame(value = x))
  }
}

result_norm <- normalize_result(result_obj)

## Ensure outputs directory exists
if (!dir.exists("outputs")) {
  dir.create("outputs", recursive = TRUE, showWarnings = FALSE)
}

## Write outputs
write.csv(result_norm, file = "outputs/result.csv", row.names = FALSE)

## Also write full result object as RDS (if needed downstream)
saveRDS(result_obj, file = "outputs/result.rds")
