#!/usr/bin/env Rscript

suppressPackageStartupMessages({
  library(dplyr)
  library(readr)
  library(purrr)
  library(stringr)
})

# Ensure outputs directory exists
if (!dir.exists("outputs")) dir.create("outputs", recursive = TRUE)

# Read table_expr.tsv
tbl_expr <- read_tsv(
  "inputs/table_expr.tsv",
  col_types = cols(.default = col_character())
)

# Evaluate expression(s) to get data object(s)
# Expect a single column named "table_expr" with R code as strings
eval_table_expr <- function(expr_chr) {
  expr_parsed <- parse(text = expr_chr)
  eval(expr_parsed, envir = .GlobalEnv)
}

objects_list <- map(tbl_expr$table_expr, eval_table_expr)

# If single expression, simplify to that object
result_obj <- if (length(objects_list) == 1) objects_list[[1]] else objects_list

# Convert result to a compact CSV-friendly form
# aNCA-compatible convention: main tabular output as is
if (is.data.frame(result_obj)) {
  out_df <- result_obj
} else if (is.vector(result_obj) && !is.list(result_obj)) {
  out_df <- tibble::tibble(value = result_obj)
} else {
  # Fallback: store structure description
  out_df <- tibble::tibble(
    index = seq_along(result_obj),
    class = vapply(result_obj, function(x) paste(class(x), collapse = ","), character(1))
  )
}

# Write CSV output
write_csv(out_df, "outputs/result.csv")

# Also write full object as RDS
saveRDS(result_obj, file = "outputs/result.rds")
