read_tsv_scalar_or_vec <- function(path, colname = NULL) {
  dt <- fread(path, sep = "\t", header = TRUE, na.strings = c("", "NA"))
  if (!is.null(colname) && colname %in% names(dt)) {
    v <- dt[[colname]]
  } else if (ncol(dt) == 1) {
    v <- dt[[1L]]
  } else {
    return(dt)
  }
  if (length(v) == 1L) {
    return(v[[1L]])
  }
  return(v)
}

