## argument to g_pkcg02_log. If g_pkcg02_log has additional formal
## arguments with length 1 and matching column names, extract them.

prepare_args_from_tsv <- function(tbl, fun) {
  fmls <- formals(fun)
  arg_names <- names(fmls)

  args <- list()

  # Prefer passing the whole table as 'data' or first argument if unnamed.
  if ("data" %in% arg_names) {
    args[["data"]] <- tbl
  } else if (length(arg_names) > 0 && arg_names[[1]] == "") {
    args[[1]] <- tbl
  } else {
    # Fallback: pass as first formal argument
    args[[arg_names[[1]]]] <- tbl
  }

  # For any remaining scalar formals that match a column name and where
  # the column is constant, pass the unique scalar value.
  remaining <- setdiff(arg_names, names(args))
  for (nm in remaining) {
    if (nm %in% names(tbl)) {
      vals <- tbl[[nm]]
      if (length(vals) == 1L || length(unique(vals[!is.na(vals)])) == 1L) {
        args[[nm]] <- vals[1L]
      }
    }
  }

  args
