  if (is.matrix(res)) {
    return(as.data.frame(res, stringsAsFactors = FALSE))
  }

  if (is.list(res)) {
    # Try to bind elements that are data.frames with compatible columns
    df_elems <- vapply(res, is.data.frame, logical(1))
    if (any(df_elems)) {
      dfs <- res[df_elems]
      same_cols <- length(unique(vapply(dfs, function(x) paste(names(x), collapse = "|"), ""))) == 1L
      if (same_cols) {
        out <- do.call(rbind, dfs)
        rownames(out) <- NULL
        return(out)
      }
    }
    # Fallback: wrap list into a data.frame, preserving structure
    return(data.frame(result = I(list(res))))
  }

  # Unknown type: wrap as list column
  data.frame(result = I(list(res)))
}

## Compact CSV writer
write_compact_csv <- function(x, file) {
  utils::write.csv(x, file = file, row.names = FALSE, na = "")
}

## ---- main ----

main <- function() {
  infile  <- file.path("inputs", "data.tsv")
  outdir  <- "outputs"
  csvfile <- file.path(outdir, "result.csv")
  rdsfile <- file.path(outdir, "result.rds")

  if (!dir.exists(outdir)) {
    dir.create(outdir, recursive = TRUE, showWarnings = FALSE)
  }

  dat <- read_tsv_keep(infile)

  if (!exists("g_pkcg02_log", mode = "function")) {
    stop("Function g_pkcg02_log is not available in the current R session.")
  }

  fun <- get("g_pkcg02_log", mode = "function")
  args <- prepare_args_from_tsv(dat, fun)

  res_raw <- do.call(fun, args)
  res_norm <- normalize_result(res_raw)

  write_compact_csv(res_norm, csvfile)
  saveRDS(res_raw, file = rdsfile)
}

if (identical(environment(), globalenv())) {
  main()
}

