## aNCA interval_remove_impute grading script

suppressPackageStartupMessages({
  library(dplyr)
  library(readr)
})

## ---- helpers ----

read_tsv_keep <- function(path) {
  readr::read_tsv(
    file = path,
    col_types = cols(.default = col_guess()),
    progress = FALSE
  )
}

## Convert 1-row data.frames to list of scalars; otherwise return as-is
df_to_args <- function(df) {
  if (nrow(df) == 1L) {
    out <- as.list(df[1, , drop = FALSE])
    return(out)
  }
  list(data = df)
}

## ---- main ----

inputs_dir  <- "inputs"
outputs_dir <- "outputs"

if (!dir.exists(outputs_dir)) dir.create(outputs_dir, recursive = TRUE)

data_path <- file.path(inputs_dir, "data.tsv")

if (!file.exists(data_path)) {
  stop("Missing required input: ", data_path)
}

data_df <- read_tsv_keep(data_path)

## ---- call interval_remove_impute ----
## Assume public aNCA routine is available on search path

if (!exists("interval_remove_impute", mode = "function")) {
  stop("Function `interval_remove_impute` not found in the current R environment.")
}

## For this task we pass the whole table as the main argument; if the routine
## expects additional scalar arguments they can be derived here as needed.
## We keep row order as provided.

args_list <- df_to_args(data_df)

res <- tryCatch(
  {
    do.call(interval_remove_impute, args_list)
  },
  error = function(e) {
    stop("interval_remove_impute call failed: ", conditionMessage(e))
  }
)

## ---- normalize result for grading ----

normalize_for_csv <- function(x) {
  if (is.data.frame(x) || is.matrix(x)) {
    as_tibble(x)
  } else if (is.list(x)) {
    # Try to build a compact, inspectable tibble:
    # - list-columns kept as-is
    # - recycle scalar elements to the length of the longest vector where possible
    lens <- vapply(x, function(col) {
      if (is.null(col)) return(0L)
      if (is.data.frame(col) || is.matrix(col)) {
        nrow(col)
      } else {
        length(col)
      }
    }, integer(1))

    max_len <- max(lens)

    norm_col <- function(col) {
      if (is.null(col)) return(rep(NA, max_len))
      if (is.data.frame(col) || is.matrix(col)) {
        if (nrow(col) == max_len) return(col)
        if (nrow(col) == 1L) return(col[rep(1L, max_len), , drop = FALSE])
        return(col[seq_len(max_len), , drop = FALSE])
      }
      if (length(col) == max_len) return(col)
      if (length(col) == 1L) return(rep(col, max_len))
      col[seq_len(max_len)]
    }

    normed <- lapply(x, norm_col)

    ## If any columns are data.frames, unnest them with prefix
    df_cols <- vapply(normed, is.data.frame, logical(1))
    if (any(df_cols)) {
      base <- normed[!df_cols]
      dfs  <- normed[df_cols]

      base_df <- as_tibble(base)
      for (nm in names(dfs)) {
        subdf <- as_tibble(dfs[[nm]])
        colnames(subdf) <- paste(nm, colnames(subdf), sep = "_")
        base_df <- bind_cols(base_df, subdf)
      }
      base_df
    } else {
      as_tibble(normed)
    }
  } else {
    tibble::tibble(value = x)
  }
}

norm_res <- normalize_for_csv(res)

## ---- write outputs ----

result_path  <- file.path(outputs_dir, "result.csv")
summary_path <- file.path(outputs_dir, "summary.csv")
rds_path     <- file.path(outputs_dir, "result.rds")

## result.csv: full normalized object (possibly truncated by grader if huge)
readr::write_csv(norm_res, result_path, na = "")

## summary.csv: compact summary of structure
summ <- tibble::tibble(
  name   = names(res),
  class  = vapply(res, function(z) paste(class(z), collapse = ","), character(1)),
  length = vapply(res, function(z) {
    if (is.data.frame(z) || is.matrix(z)) nrow(z) else length(z)
  }, numeric(1))
)
readr::write_csv(summ, summary_path, na = "")

## full R object
saveRDS(res, rds_path)
