  read.delim(path, header = TRUE, sep = "\t", check.names = FALSE, stringsAsFactors = FALSE)
}

# Helper: convert 1-row tables that represent simple vectors to vector/scalar
one_row_to_vec <- function(df) {
  if (nrow(df) == 1L) {
    as.character(unlist(df[1, ], use.names = FALSE))
  } else {
    df
  }
}

# Read inputs
conc_col_df  <- read_tsv(file.path(in_dir, "conc_col.tsv"))
data_df      <- read_tsv(file.path(in_dir, "data.tsv"))
groups_df    <- read_tsv(file.path(in_dir, "groups.tsv"))
matrix_col_df<- read_tsv(file.path(in_dir, "matrix_col.tsv"))
spec1_df     <- read_tsv(file.path(in_dir, "spec1.tsv"))
spec2_df     <- read_tsv(file.path(in_dir, "spec2.tsv"))
