partial_path <- file.path("inputs", "partial.tsv")
out_csv_path <- file.path("outputs", "adjusted_dtc.csv")
out_rds_path <- file.path("outputs", "adjusted_dtc.rds")

# ---- Read inputs with validation ----

stop_if_not_file(imputed_path)
stop_if_not_file(partial_path)

imputed_df <- tryCatch(
  read.delim(imputed_path, stringsAsFactors = FALSE),
  error = function(e) stop("Error reading imputed_dtc.tsv: ", conditionMessage(e))
)

partial_df <- tryCatch(
  read.delim(partial_path, stringsAsFactors = FALSE),
  error = function(e) stop("Error reading partial.tsv: ", conditionMessage(e))
)

validate_column(imputed_df, "dtc", "imputed_dtc.tsv")
validate_column(partial_df, "partial", "partial.tsv")

imputed_vec <- imputed_df$dtc
partial_vec <- partial_df$partial

check_lengths_equal(imputed_vec, partial_vec)

# ---- Convert partial to admiral-style partial list ----
# Using convert_dtc_to_dtm for robust parsing; we only need components

partial_list <- lapply(
  partial_vec,
  function(x) {
    if (is.na(x) || trimws(x) == "") {
      return(list(year = NA_integer_, month = NA_integer_, day = NA_integer_))
    }

    # Try parsing as date or datetime; fall back to manual split if needed
    dt <- tryCatch(
      convert_dtc_to_dtm(x, highest_imputation = "d"),
      error = function(e) NA
    )

    if (all(is.na(dt))) {
      # Manual parse of partial DTC: yyyy[-mm[-dd]]
      parts <- strsplit(x, "-", fixed = TRUE)[[1]]
      year  <- suppressWarnings(as.integer(parts[1]))
      month <- if (length(parts) >= 2) suppressWarnings(as.integer(parts[2])) else NA_integer_
      day   <- if (length(parts) >= 3) suppressWarnings(as.integer(parts[3])) else NA_integer_
      return(list(year = year, month = month, day = day))
    } else {
      yr <- as.integer(format(dt, "%Y"))
      mo <- as.integer(format(dt, "%m"))
      dy <- as.integer(format(dt, "%d"))
      # If original string is partial, some components may be imputed by convert_dtc_to_dtm.
      # Detect missing parts by counting dashes.
      n_dash <- nchar(gsub("[^\\-]", "", x))
      if (n_dash < 2) dy <- NA_integer_
      if (n_dash < 1) mo <- NA_integer_
      list(year = yr, month = mo, day = dy)
    }
  }
)

