  }
  df <- tryCatch(
    read.delim(path, stringsAsFactors = FALSE, check.names = FALSE),
    error = function(e) stop(sprintf("Failed to read %s: %s", path, e$message))
  )
  if (!is.data.frame(df) || ncol(df) != 1L || names(df)[1] != expected_col) {
    stop(sprintf(
      "File %s must contain exactly one column named '%s'.",
      path, expected_col
    ))
  }
  if (nrow(df) != 1L) {
    stop(sprintf(
      "File %s must contain exactly one row; found %d rows.",
      path, nrow(df)
    ))
