  readRDS(out_rds),
  error = function(e) stop(sprintf("Failed to re-read RDS output: %s", e$message))
)

if (!is.data.frame(csv_check) || !is.data.frame(rds_check)) {
  stop("Re-read outputs are not data.frames, indicating possible write/read issues.")
}
