    read.csv(csv_path, stringsAsFactors = FALSE),
    error = function(e) stop("Failed to read back CSV file: ", csv_path, " | Error: ", conditionMessage(e))
  )

  df_rds <- tryCatch(
    readRDS(rds_path),
    error = function(e) stop("Failed to read back RDS file: ", rds_path, " | Error: ", conditionMessage(e))
  )

  if (!all(names(df_csv) == names(df))) {
    stop("Column names mismatch after CSV roundtrip for file: ", csv_path)
  }
  if (!all(names(df_rds) == names(df))) {
    stop("Column names mismatch after RDS roundtrip for file: ", rds_path)
  }

