height_path <- file.path("inputs", "height.tsv")
weight_path <- file.path("inputs", "weight.tsv")

if (!file.exists(height_path)) stop("Height file not found: ", height_path)
if (!file.exists(weight_path)) stop("Weight file not found: ", weight_path)

height_df <- tryCatch(
  read.table(height_path, header = TRUE, sep = "\t", stringsAsFactors = FALSE),
  error = function(e) stop("Error reading height.tsv: ", e$message)
)

weight_df <- tryCatch(
  read.table(weight_path, header = TRUE, sep = "\t", stringsAsFactors = FALSE),
  error = function(e) stop("Error reading weight.tsv: ", e$message)
)

# Basic structure checks
if (!("height" %in% names(height_df))) {
  stop("Column 'height' not found in height.tsv")
}
if (!("weight" %in% names(weight_df))) {
  stop("Column 'weight' not found in weight.tsv")
}

# Ensure numeric
height_df$height <- suppressWarnings(as.numeric(height_df$height))
weight_df$weight <- suppressWarnings(as.numeric(weight_df$weight))

if (any(is.na(height_df$height))) {
  stop("Non-numeric or missing values detected in 'height' column")
}
if (any(is.na(weight_df$weight))) {
  stop("Non-numeric or missing values detected in 'weight' column")
}

# Check lengths for alignment
n_h <- nrow(height_df)
n_w <- nrow(weight_df)

if (n_h != n_w) {
  stop(
    "Row count mismatch between height (", n_h, 
    ") and weight (", n_w, "). Possible data misalignment."
  )
}

# Check for reasonable ranges
if (any(height_df$height <= 0 | height_df$height > 300)) {
  stop("Unreasonable height values detected (must be in cm and >0, <=300).")
}
if (any(weight_df$weight <= 0 | weight_df$weight > 500)) {
  stop("Unreasonable weight values detected (must be in kg and >0, <=500).")
}

##---------------------------
## 2. Prepare data and compute BMI using admiral
##---------------------------

# Combine into a single aligned data frame
bmi_input <- data.frame(
  USUBJID = seq_len(n_h),           # artificial ID to keep rows aligned
  HEIGHT  = height_df$height,       # cm
  WEIGHT  = weight_df$weight        # kg
)

# Compute BMI (kg/m^2); admiral::compute_bmi expects height in cm and weight in kg
bmi_input$BMI <- compute_bmi(
  height = bmi_input$HEIGHT,
  weight = bmi_input$WEIGHT
)

##---------------------------
## 3. Validate BMI results
##---------------------------

# Check for missing or implausible BMI values
if (any(is.na(bmi_input$BMI))) {
  stop("Missing BMI values produced; check input data.")
}

# BMI in kg/m^2; typical human range ~10–80 (allowing wide margin)
if (any(bmi_input$BMI <= 5 | bmi_input$BMI > 100)) {
  warning("Implausible BMI values detected; possible data or parsing issues.")
}

# Simple pattern check: very strong outliers or identical values
if (length(unique(round(bmi_input$BMI, 2))) == 1L) {
  warning("All BMI values are (almost) identical; possible misalignment.")
}

##---------------------------
## 4. Save outputs
##---------------------------

bmi_csv_path <- file.path("outputs", "bmi.csv")
bmi_rds_path <- file.path("outputs", "bmi.rds")

# Save as CSV (data frame)
write.csv(bmi_input, bmi_csv_path, row.names = FALSE)

# Save as RDS (complex object support)
saveRDS(bmi_input, bmi_rds_path)

##---------------------------
## 5. Confirm outputs written
##---------------------------

if (!file.exists(bmi_csv_path)) {
  stop("BMI CSV file was not written correctly: ", bmi_csv_path)
}
if (!file.exists(bmi_rds_path)) {
  stop("BMI RDS file was not written correctly: ", bmi_rds_path)
}

# Re-read CSV and do a quick consistency check
bmi_check <- tryCatch(
  read.csv(bmi_csv_path, stringsAsFactors = FALSE),
  error = function(e) stop("Error re-reading BMI CSV: ", e$message)
)

if (nrow(bmi_check) != nrow(bmi_input)) {
  stop("Row count mismatch between in-memory BMI data and saved CSV; possible write/read issue.")
}

if (!all.equal(bmi_check$BMI, bmi_input$BMI, tolerance = 1e-8)) {
  warning("BMI values differ between in-memory object and CSV; check for formatting or rounding issues.")
}
