library(admiral)

# Create output directory if it does not exist
if (!dir.exists("outputs")) {
  dir.create("outputs", recursive = TRUE)
}

#-----------------------------
# Helper: Safe file reader
#-----------------------------
read_input_tsv <- function(path, expected_col) {
  if (!file.exists(path)) {
    stop(paste0("Input file not found: ", path))
  }
  dat <- tryCatch(
    read.delim(path, header = TRUE, stringsAsFactors = FALSE, check.names = FALSE),
    error = function(e) stop(paste0("Failed to read ", path, ": ", e$message))
  )
  if (!expected_col %in% names(dat)) {
    stop(paste0("Expected column '", expected_col, "' not found in ", path))
  }
  if (!is.numeric(dat[[expected_col]])) {
    stop(paste0("Column '", expected_col, "' in ", path, " must be numeric"))
  }
  dat
}

#-----------------------------
# Read and validate inputs
#-----------------------------
diabp_df <- read_input_tsv("inputs/diabp.tsv", "diabp")
sysbp_df <- read_input_tsv("inputs/sysbp.tsv", "sysbp")
hr_df    <- read_input_tsv("inputs/hr.tsv", "hr")

n_diabp <- nrow(diabp_df)
n_sysbp <- nrow(sysbp_df)
n_hr    <- nrow(hr_df)

if (!identical(n_diabp, n_sysbp) || !identical(n_diabp, n_hr)) {
  stop(
    paste(
      "Row count mismatch among input files:",
      "diabp =", n_diabp,
      "sysbp =", n_sysbp,
      "hr =", n_hr
    )
  )
}

# Extract numeric vectors
diabp_vec <- diabp_df$diabp
sysbp_vec <- sysbp_df$sysbp
hr_vec    <- hr_df$hr

#-----------------------------
# Data validation
#-----------------------------
validate_vector <- function(x, name) {
  if (any(!is.finite(x))) {
    stop(paste0("Non-finite values detected in ", name))
  }
}

validate_vector(diabp_vec, "diabp")
validate_vector(sysbp_vec, "sysbp")
validate_vector(hr_vec, "hr")

#-----------------------------
# Compute MAP
#-----------------------------
# Using only diastolic and systolic BP
map_dbp_sbp <- compute_map(
  diabp = diabp_vec,
  sysbp = sysbp_vec,
  hr = NULL
)

# Using diastolic, systolic BP, and heart rate
map_dbp_sbp_hr <- compute_map(
  diabp = diabp_vec,
  sysbp = sysbp_vec,
  hr = hr_vec
)

#-----------------------------
# Assemble outputs
#-----------------------------
map_df <- data.frame(
  diabp = diabp_vec,
  sysbp = sysbp_vec,
  hr = hr_vec,
  map_dbp_sbp = map_dbp_sbp,
  map_dbp_sbp_hr = map_dbp_sbp_hr,
  stringsAsFactors = FALSE
)

#-----------------------------
# Basic checks for unexpected patterns
#-----------------------------
if (any(is.na(map_dbp_sbp))) {
  stop("NA values detected in MAP (diabp + sysbp) result; possible data issue.")
}
if (any(is.na(map_dbp_sbp_hr))) {
  stop("NA values detected in MAP (diabp + sysbp + hr) result; possible data issue.")
}
if (length(map_dbp_sbp) != n_diabp || length(map_dbp_sbp_hr) != n_diabp) {
  stop("Length of computed MAP vectors does not match input length.")
}

# Quick range checks (not strict limits, just sanity checks)
if (any(map_dbp_sbp < 0) || any(map_dbp_sbp_hr < 0)) {
  warning("Negative MAP values detected; check input data or units.")
}

#-----------------------------
# Write outputs
#-----------------------------
out_csv_path <- "outputs/map_results.csv"
out_rds_path <- "outputs/map_results.rds"

tryCatch(
  {
    write.csv(map_df, file = out_csv_path, row.names = FALSE)
  },
  error = function(e) stop(paste0("Failed to write CSV: ", e$message))
)

tryCatch(
  {
    saveRDS(map_df, file = out_rds_path)
  },
  error = function(e) stop(paste0("Failed to write RDS: ", e$message))
)

#-----------------------------
# Confirm outputs written correctly
#-----------------------------
if (!file.exists(out_csv_path)) {
  stop("CSV output file was not created.")
}
if (!file.exists(out_rds_path)) {
  stop("RDS output file was not created.")
}

# Re-read and basic sanity check
map_df_csv <- tryCatch(
  read.csv(out_csv_path, stringsAsFactors = FALSE),
  error = function(e) stop(paste0("Failed to re-read CSV: ", e$message))
)

map_df_rds <- tryCatch(
  readRDS(out_rds_path),
  error = function(e) stop(paste0("Failed to re-read RDS: ", e$message))
)

if (!all.equal(map_df, map_df_csv, check.attributes = FALSE)) {
  warning("Data frame read back from CSV does not exactly match original (possible formatting differences).")
}
if (!all.equal(map_df, map_df_rds, check.attributes = FALSE)) {
  warning("Data frame read back from RDS does not exactly match original.")
}
