# Helper: safe TSV reader
#--------------------------
read_input_tsv <- function(path, expected_col, type = c("character", "numeric", "logical")) {
  type <- match.arg(type)
  if (!file.exists(path)) {
    stop(sprintf("Input file not found: %s", path))
  }
  df <- tryCatch(
    read.csv(path, sep = "\t", header = TRUE, stringsAsFactors = FALSE),
    error = function(e) stop(sprintf("Error reading %s: %s", path, e$message))
  )
  if (!(expected_col %in% names(df))) {
    stop(sprintf("Expected column '%s' not found in %s", expected_col, path))
  }
  vec <- df[[expected_col]]

  if (type == "character") {
    vec <- as.character(vec)
  } else if (type == "numeric") {
    suppressWarnings(vec_num <- as.numeric(vec))
    if (any(is.na(vec_num) & !is.na(vec))) {
      warning(sprintf("Non-numeric values coerced to NA in %s", path))
    }
    vec <- vec_num
  } else if (type == "logical") {
    # Interpret typical logical encodings if needed
    if (is.logical(vec)) {
      return(vec)
    }
    lv <- tolower(as.character(vec))
    logical_vec <- ifelse(lv %in% c("true", "t", "1", "yes", "y"), TRUE,
                   ifelse(lv %in% c("false", "f", "0", "no", "n"), FALSE, NA))
    if (any(is.na(logical_vec) & !is.na(vec))) {
      warning(sprintf("Non-logical values coerced to NA in %s", path))
    }
    vec <- logical_vec
  }

  vec
