  }
  df <- tryCatch(
    read.delim(path, header = TRUE, sep = "\t", stringsAsFactors = FALSE, check.names = FALSE),
    error = function(e) stop(paste0("Failed to read ", path, ": ", e$message))
  )
  if (!is.null(colname_expected)) {
