library(admiral)

# Helper: safe TSV reader with basic validation
read_tsv_safe <- function(path, ...) {
  if (!file.exists(path)) {
    stop("Input file not found: ", path)
  }
  df <- tryCatch(
    read.delim(path, header = TRUE, sep = "\t", stringsAsFactors = FALSE, ...),
    error = function(e) stop("Failed to read TSV file: ", path, " | ", e$message)
  )
  if (!is.data.frame(df)) {
    stop("File did not produce a data.frame: ", path)
  }
  df
}

# Load inputs ---------------------------------------------------------------

