by_vars  <- read_tsv_safe(by_vars_path)
method_df <- read_tsv_safe(method_path)
qt_code_df <- read_tsv_safe(qt_code_path)
rr_code_df <- read_tsv_safe(rr_code_path)
get_unit_expr_df <- read_tsv_safe(get_unit_expr_path)

# Validate required columns for datase
required_datase_vars <- c("USUBJID", "PARAMCD", "AVAL")
missing_datase <- setdiff(required_datase_vars, names(datase))
if (length(missing_datase) > 0) {
  stop("datase is missing required variables: ", paste(missing_datase, collapse = ", "))
}

# Validate by_vars content
if (!"by_vars" %in% names(by_vars)) {
  stop("by_vars.tsv must contain a column named 'by_vars'")
}
by_vars_vec <- unique(trimws(by_vars$by_vars))
by_vars_vec <- by_vars_vec[by_vars_vec != ""]
missing_by <- setdiff(by_vars_vec, names(datase))
if (length(missing_by) > 0) {
  stop("Variables listed in by_vars.tsv not found in datase: ",
       paste(missing_by, collapse = ", "))
}

# Determine method (single value expected)
if (!"method" %in% names(method_df)) {
  stop("method.tsv must contain a column named 'method'")
}
method_vec <- unique(trimws(method_df$method))
method_vec <- method_vec[method_vec != ""]
if (length(method_vec) != 1) {
  stop("method.tsv must contain exactly one non-empty method value")
}
method_val <- method_vec[[1]]

# Extract code strings for qt_code and rr_code -----------------------------

if (!"code" %in% names(qt_code_df)) {
  stop("qt_code.tsv must contain a column named 'code'")
}
qt_code_str <- paste(qt_code_df$code, collapse = "\n")

if (!"code" %in% names(rr_code_df)) {
  stop("rr_code.tsv must contain a column named 'code'")
}
rr_code_str <- paste(rr_code_df$code, collapse = "\n")

# In a realistic setting, qt_code and rr_code would be PARAMCD values (e.g. "QT", "RR").
# Here we defensively ensure they are character scalar values even though the preview
# shows they currently contain R code, which will not match any PARAMCD.
qt_code_val <- trimws(qt_code_str)
