#-----------------------------
# Helper functions
#-----------------------------

stop_if_any_na <- function(df, vars, df_name = "dataset") {
  missing_cols <- setdiff(vars, names(df))
  if (length(missing_cols) > 0) {
    stop(
      sprintf(
        "Required columns %s not found in %s.",
        paste(missing_cols, collapse = ", "),
        df_name
      ),
      call. = FALSE
    )
  }

  na_summary <- df %>%
    summarise(across(all_of(vars), ~ sum(is.na(.x)))) %>%
    tidyr::pivot_longer(everything(), names_to = "var", values_to = "n_na") %>%
    filter(n_na > 0)

  if (nrow(na_summary) > 0) {
    msg <- paste0(
      "NA values detected in required columns:\n",
      paste0(na_summary$var, ": ", na_summary$n_na, " NAs", collapse = "\n")
    )
    warning(msg, call. = FALSE)
  }
}

check_pchg_calculation <- function(df, tol = 1e-4) {
  if (!all(c("AVAL", "BASE", "CHG", "PCHG") %in% names(df))) {
    warning("Cannot check PCHG calculation: required variables missing.", call. = FALSE)
    return(invisible(NULL))
  }

  df_check <- df %>%
    mutate(
      PCHG_expected = if_else(
        !is.na(BASE) & BASE != 0,
        CHG / abs(BASE) * 100,
        NA_real_
      ),
      diff = PCHG - PCHG_expected
    )

  large_diff <- df_check %>%
    filter(!is.na(diff) & abs(diff) > tol)

  if (nrow(large_diff) > 0) {
    warning(
      paste0(
        "Detected ", nrow(large_diff),
        " records where derived PCHG differs from expected by > ",
        tol, ". Possible data misalignment or parsing issue."
      ),
      call. = FALSE
    )
  }

  invisible(NULL)
}

