if (!"source_var" %in% names(source_spec)) {
  stop("`source_vars.tsv` must contain a column named `source_var`.")
}

# Coerce to character, drop NAs/empties, get unique variable names
source_var_names <- source_spec %>%
  mutate(source_var = as.character(source_var)) %>%
  filter(!is.na(source_var), source_var != "") %>%
  distinct(source_var) %>%
  pull(source_var)

if (length(source_var_names) == 0) {
  stop("No valid source variables found in `source_vars.tsv`.")
}

# Ensure all listed vars exist in datase
missing_vars <- setdiff(source_var_names, names(datase))
if (length(missing_vars) > 0) {
