source_vars_exprs <- rlang::exprs(!!!rlang::syms(source_var_names))

#--- Apply derive_vars_dtm_to_dt ----------------------------------------------

datase_dt <- tryCatch(
  {
    admiral::derive_vars_dtm_to_dt(
      dataset    = datase,
      source_vars = source_vars_exprs
    )
