#-----------------------------
# Helper: safe read of TSV
#-----------------------------
safe_read_tsv <- function(path, expected_cols = NULL) {
  if (!file.exists(path)) {
    stop(sprintf("Input file not found: %s", path))
  }
  df <- tryCatch(
    read.delim(path, sep = "\t", stringsAsFactors = FALSE, check.names = FALSE),
    error = function(e) stop(sprintf("Failed to read %s: %s", path, e$message))
  )
  if (!is.null(expected_cols)) {
    missing_cols <- setdiff(expected_cols, names(df))
    if (length(missing_cols) > 0) {
      stop(sprintf(
        "File %s is missing expected columns: %s",
        path, paste(missing_cols, collapse = ", ")
      ))
    }
  }
  df
}

#-----------------------------
# Read and validate inputs
#-----------------------------
cond_df <- safe_read_tsv("inputs/cond.tsv", expected_cols = "cond")
is_df   <- safe_read_tsv("inputs/is.tsv",   expected_cols = "is")
var_df  <- safe_read_tsv("inputs/var.tsv",  expected_cols = "by_vars")

if (nrow(cond_df) != 1) {
  stop("cond.tsv must contain exactly one row with a single condition string.")
}

# Basic content validation
if (any(!nzchar(trimws(cond_df$cond)))) {
  stop("cond column contains empty/blank condition strings.")
}
if (any(!nzchar(trimws(is_df$is)))) {
  stop("is column contains empty/blank values.")
}
if (any(!nzchar(trimws(var_df$by_vars)))) {
  stop("by_vars column contains empty/blank variable names.")
}

# Take the first (and only) base condition
base_cond <- cond_df$cond[1]

# For safety, ensure single variable (as described by problem)
if (nrow(var_df) != 1) {
  stop("var.tsv must contain exactly one row specifying a single variable name.")
}
var_name <- var_df$by_vars[1]

#-----------------------------
# Build extended conditions
#-----------------------------
# For each value in is.tsv, extend the base condition using admiral::extend_condition
extended_conditions <- lapply(seq_len(nrow(is_df)), function(i) {
  value <- is_df$is[i]
  # Skip obviously problematic cases
  if (!nzchar(trimws(value))) {
    stop(sprintf("Row %d in is.tsv has an empty value.", i))
  }
  admiral::extend_condition(
    cond = base_cond,
    var  = var_name,
    is   = value
  )
})

# Convert to character vector
extended_conditions <- unlist(extended_conditions, use.names = FALSE)

# Wrap into a data frame for CSV output
extended_df <- data.frame(
  cond_id   = seq_along(extended_conditions),
  base_cond = base_cond,
  var       = var_name,
  is        = is_df$is,
  extended  = extended_conditions,
  stringsAsFactors = FALSE
)

#-----------------------------
# Basic sanity checks
#-----------------------------
# Check for NA or empty results
if (any(is.na(extended_df$extended))) {
  stop("Extended condition contains NA values, indicating a possible parsing issue.")
}
if (any(!nzchar(trimws(extended_df$extended)))) {
  stop("Extended condition contains empty/blank strings, indicating a possible parsing issue.")
}

# Very simple pattern check: each extended condition must at least contain the base condition
