# Helper: safe read of TSV
#-----------------------------
safe_read_tsv <- function(path, expected_cols = NULL) {
  if (!file.exists(path)) {
    stop(sprintf("Input file not found: %s", path))
  }
  df <- tryCatch(
    read.delim(path, sep = "\t", stringsAsFactors = FALSE, check.names = FALSE),
    error = function(e) stop(sprintf("Failed to read %s: %s", path, e$message))
  )
  if (!is.null(expected_cols)) {
    missing_cols <- setdiff(expected_cols, names(df))
    if (length(missing_cols) > 0) {
      stop(sprintf(
        "File %s is missing expected columns: %s",
        path, paste(missing_cols, collapse = ", ")
