  orig_by <- unique(src_main[by_vars_vec])
  if (any(complete.cases(orig_by))) {
    na_by_rows <- !complete.cases(ds[by_vars_vec])
    if (any(na_by_rows)) {
      warning(
        sprintf(
          "Dataset '%s' contains rows with NA in by_vars after extension; possible misalignment.",
          nm
        )
      )
    }
  }
}
