order_path      <- file.path("inputs", "order.tsv")
mode_path       <- file.path("inputs", "mode.tsv")
check_type_path <- file.path("inputs", "check_type.tsv")

if (!all(file.exists(dataset_path, by_vars_path, order_path, mode_path, check_type_path))) {
  stop("One or more required input files are missing in 'inputs/' directory.")
}

