# Helper: safe file write with basic checks
safe_write <- function(df, csv_path, rds_path) {
  stopifnot(is.data.frame(df))
  write_csv(df, csv_path, na = "")
  saveRDS(df, rds_path)
  # Basic confirmation and structural checks
  chk_csv <- try(suppressMessages(read_csv(csv_path, show_col_types = FALSE)), silent = TRUE)
  chk_rds <- try(readRDS(rds_path), silent = TRUE)
  if (inherits(chk_csv, "try-error") || inherits(chk_rds, "try-error")) {
    stop("Error while re-reading written output files; possible write/parsing issue.")
  }
  if (!is.data.frame(chk_csv) || !is.data.frame(chk_rds)) {
    stop("Re-read objects are not data frames; possible corruption or type change.")
  }
  if (!identical(names(df), names(chk_csv)) || !identical(names(df), names(chk_rds))) {
    stop("Column names changed after write/read; possible misalignment.")
