library(admiral)

# ---- Helper functions ----

validate_option_name <- function(opt) {
  if (!is.character(opt) || length(opt) != 1L || is.na(opt) || opt == "") {
    stop("Invalid option name: must be a non-empty character scalar.")
  }
  opt
}

get_option_value_safely <- function(opt) {
  validate_option_name(opt)
  tryCatch(
    {
      val <- get_admiral_option(option = opt)
      if (is.null(val)) {
        stop(sprintf("get_admiral_option('%s') returned NULL.", opt))
      }
      val
    },
    error = function(e) {
      stop(sprintf("Error retrieving admiral option '%s': %s", opt, e$message), call. = FALSE)
    }
  )
}

write_output <- function(value, name) {
  out_dir <- "outputs"
  if (!dir.exists(out_dir)) dir.create(out_dir, recursive = TRUE)

  if (is.data.frame(value)) {
    file <- file.path(out_dir, paste0(name, ".csv"))
    write.csv(value, file = file, row.names = FALSE)
  } else {
    file <- file.path(out_dir, paste0(name, ".rds"))
    saveRDS(value, file = file)
  }

  if (!file.exists(file)) {
    stop(sprintf("Output file for option '%s' was not written: %s", name, file))
  }

  file
}

basic_sanity_check <- function(value, opt_name) {
  if (is.data.frame(value)) {
    if (nrow(value) == 0L) {
      warning(sprintf("Option '%s' resulted in an empty data frame.", opt_name))
    }
    if (any(duplicated(names(value)))) {
      warning(sprintf("Option '%s' data frame has duplicated column names.", opt_name))
    }
  } else if (is.atomic(value) && length(value) == 0L) {
    warning(sprintf("Option '%s' resulted in an empty atomic vector.", opt_name))
  }
  invisible(TRUE)
}

# ---- Main script ----

