}

opt_vec <- unique(trimws(opt_df$option))

results <- list()
files_written <- character()

for (opt in opt_vec) {
  val <- get_option_value_safely(opt)
  basic_sanity_check(val, opt)
  file <- write_output(val, opt)
  files_written <- c(files_written, file)
  results[[opt]] <- val
}

# Final verification of all written files
for (f in files_written) {
  if (!file.exists(f)) {
    stop("Verification failed: expected output file missing: ", f)
  }
  # Lightweight read-back check
  tryCatch(
    {
      if (grepl("\\.csv$", f, ignore.case = TRUE)) {
        tmp <- read.csv(f, stringsAsFactors = FALSE, check.names = FALSE)
        if (!is.data.frame(tmp)) stop("Read-back is not a data frame.")
      } else if (grepl("\\.rds$", f, ignore.case = TRUE)) {
        tmp <- readRDS(f)
        if (is.null(tmp)) stop("Read-back object is NULL.")
      }
    },
    error = function(e) {
      stop("Read-back verification failed for ", f, ": ", e$message)
    }
  )
)

