library(admiral)
library(dplyr)
library(readr)
library(rlang)
library(purrr)

#--- Helper: safe read_tsv that errors clearly ---------------------------------
safe_read_tsv <- function(path, ...) {
  tryCatch(
    readr::read_tsv(path, show_col_types = FALSE, progress = FALSE, ...),
    error = function(e) {
      stop("Error reading file: ", path, "\n", conditionMessage(e), call. = FALSE)
    }
  )
}

#--- Read inputs ---------------------------------------------------------------
dat_path              <- "inputs/dataset.tsv"
by_vars_path          <- "inputs/by_vars.tsv"
order_path            <- "inputs/order.tsv"
condition_path        <- "inputs/condition.tsv"
mode_path             <- "inputs/mode.tsv"
selection_path        <- "inputs/selection.tsv"
inclusive_path        <- "inputs/inclusive.tsv"
keep_no_ref_groups_path <- "inputs/keep_no_ref_groups.tsv"
check_type_path       <- "inputs/check_type.tsv"

adsl <- safe_read_tsv(dat_path)

by_vars_df    <- safe_read_tsv(by_vars_path)
order_df      <- safe_read_tsv(order_path)
condition_df  <- safe_read_tsv(condition_path)
mode_df       <- safe_read_tsv(mode_path)
selection_df  <- safe_read_tsv(selection_path)
inclusive_df  <- safe_read_tsv(inclusive_path)
keep_no_ref_df<- safe_read_tsv(keep_no_ref_groups_path)
check_type_df <- safe_read_tsv(check_type_path)

#--- Basic validation ----------------------------------------------------------
required_cols <- c("USUBJID", "AVAL", "AVISITN", "ADT")
missing_in_adsl <- setdiff(required_cols, names(adsl))
if (length(missing_in_adsl) > 0) {
  stop("Missing required columns in dataset.tsv: ",
       paste(missing_in_adsl, collapse = ", "),
       call. = FALSE)
}

# by_vars
if (!"by_vars" %in% names(by_vars_df)) {
  stop("by_vars.tsv must contain column 'by_vars'", call. = FALSE)
}
by_vars <- unique(na.omit(by_vars_df$by_vars))
if (length(by_vars) == 0) {
  stop("No by variables specified in by_vars.tsv", call. = FALSE)
}
missing_by <- setdiff(by_vars, names(adsl))
if (length(missing_by) > 0) {
  stop("by_vars not present in dataset: ",
       paste(missing_by, collapse = ", "),
       call. = FALSE)
}

# order
if (!"order" %in% names(order_df)) {
  stop("order.tsv must contain column 'order'", call. = FALSE)
}
order_vars <- unique(na.omit(order_df$order))
if (length(order_vars) == 0) {
  stop("No order variables specified in order.tsv", call. = FALSE)
}
missing_order <- setdiff(order_vars, names(adsl))
if (length(missing_order) > 0) {
  stop("order vars not present in dataset: ",
       paste(missing_order, collapse = ", "),
       call. = FALSE)
}

# condition
if (!"cond" %in% names(condition_df)) {
  stop("condition.tsv must contain column 'cond'", call. = FALSE)
}
cond_str <- condition_df$cond[1]
if (is.na(cond_str) || !nzchar(cond_str)) {
  stop("Empty condition expression in condition.tsv", call. = FALSE)
}
# Parse condition safely
condition_expr <- tryCatch(
  rlang::parse_expr(cond_str),
  error = function(e) {
    stop("Unable to parse condition expression: '", cond_str, "'\n",
         conditionMessage(e), call. = FALSE)
  }
)

# mode
if (!"mode" %in% names(mode_df)) {
  stop("mode.tsv must contain column 'mode'", call. = FALSE)
}
mode_val <- mode_df$mode[1]
if (is.na(mode_val) || !mode_val %in% c("first", "last")) {
  stop("mode must be 'first' or 'last' in mode.tsv", call. = FALSE)
}

# selection, inclusive, keep_no_ref_groups:
# Provided files contain variable names in several rows. For this task,
# we map them to scalar logical/character parameters using simple rules.
# Here we choose a fixed, reasonable configuration and ignore the lists:
#   selection = "after"
#   inclusive = TRUE
#   keep_no_ref_groups = TRUE
selection_val <- "after"
inclusive_val <- TRUE
keep_no_ref_groups_val <- TRUE

# check_type
if (!"check_type" %in% names(check_type_df)) {
  stop("check_type.tsv must contain column 'check_type'", call. = FALSE)
}
check_type_val <- check_type_df$check_type[1]
if (is.na(check_type_val) || !check_type_val %in% c("none", "warning", "error")) {
  stop("check_type must be one of 'none', 'warning', 'error' in check_type.tsv",
       call. = FALSE)
}

#--- Build by_vars and order quosures -----------------------------------------
by_vars_syms   <- rlang::syms(by_vars)

# Use exprs(ADT, desc(AVAL)) as per user example
order_quos <- exprs(ADT, desc(AVAL))

#--- Run filter_relative ------------------------------------------------------
# Ensure ADT is a proper date
if (!inherits(adsl$ADT, "Date")) {
  adsl <- mutate(adsl, ADT = as.Date(ADT))
}

result <- tryCatch(
  {
    filter_relative(
      dataset          = adsl,
      by_vars          = exprs(!!!by_vars_syms),
      order            = order_quos,
      condition        = !!condition_expr,
      mode             = mode_val,
      selection        = selection_val,
      inclusive        = inclusive_val,
      keep_no_ref_groups = keep_no_ref_groups_val,
      check_type       = check_type_val
    )
  },
  error = function(e) {
    stop("filter_relative failed: ", conditionMessage(e), call. = FALSE)
  }
)

#--- Basic sanity checks on result --------------------------------------------
if (!is.data.frame(result)) {
  stop("Result of filter_relative is not a data.frame", call. = FALSE)
}
if (nrow(result) == 0) {
  warning("Result dataset has 0 rows after filtering.")
}
if (any(!by_vars %in% names(result))) {
  warning("Some by_vars are missing from the result dataset.")
}

# Simple pattern checks: compare USUBJID counts pre vs post
pre_counts  <- adsl %>% count(USUBJID, name = "n_pre")
post_counts <- result %>% count(USUBJID, name = "n_post")

merged_counts <- full_join(pre_counts, post_counts, by = "USUBJID")

if (any(is.na(merged_counts$n_post))) {
  warning("Some subjects are missing in the result dataset compared to input.")
}
if (any(merged_counts$n_post > merged_counts$n_pre, na.rm = TRUE)) {
  warning("Some subjects have more records post-filter than pre-filter (unexpected).")
}

#--- Write outputs ------------------------------------------------------------
out_dir <- "outputs"
if (!dir.exists(out_dir)) {
  dir.create(out_dir, recursive = TRUE)
}

csv_path <- file.path(out_dir, "filtered_relative.csv")
rds_path <- file.path(out_dir, "filtered_relative.rds")

readr::write_csv(result, csv_path, na = "")
saveRDS(result, rds_path)

#--- Confirm that files were written correctly --------------------------------
if (!file.exists(csv_path)) {
  stop("CSV output file was not created: ", csv_path, call. = FALSE)
}
if (!file.exists(rds_path)) {
  stop("RDS output file was not created: ", rds_path, call. = FALSE)
}

test_csv <- tryCatch(
  suppressMessages(readr::read_csv(csv_path, show_col_types = FALSE)),
  error = function(e) {
    stop("Unable to re-read CSV output file (possible corruption): ",
         conditionMessage(e), call. = FALSE)
  }
)

test_rds <- tryCatch(
  readRDS(rds_path),
  error = function(e) {
    stop("Unable to read RDS output file (possible corruption): ",
         conditionMessage(e), call. = FALSE)
  }
)

if (!is.data.frame(test_csv) || !is.data.frame(test_rds)) {
  stop("Output files do not contain data frames as expected.", call. = FALSE)
}

# Quick structural comparison
if (!identical(names(result), names(test_csv))) {
  warning("Column names differ between in-memory result and CSV reload; check for delimiter/quote issues.")
}
if (!identical(names(result), names(test_rds))) {
  warning("Column names differ between in-memory result and RDS reload; check save/load logic.")
}
