#---------------------------
# Helper functions
#---------------------------
stop_if_invalid_scalar_char <- function(x, nm) {
  if (!is.character(x) || length(x) != 1 || is.na(x) || nchar(trimws(x)) == 0) {
    stop(sprintf("`%s` must be a non-empty character scalar.", nm), call. = FALSE)
  }
}

stop_if_invalid_scalar_logical <- function(x, nm) {
  if (!is.logical(x) || length(x) != 1 || is.na(x)) {
    stop(sprintf("`%s` must be a non-missing logical scalar.", nm), call. = FALSE)
  }
}

safe_read_tsv_single_value <- function(path, col_name_expected, type = c("character", "logical")) {
  type <- match.arg(type)
  if (!file.exists(path)) {
    stop(sprintf("Input file not found: %s", path), call. = FALSE)
  }

  df <- tryCatch(
    utils::read.table(
      file = path,
      header = TRUE,
      sep = "\t",
      quote = "",
      comment.char = "",
      stringsAsFactors = FALSE,
      check.names = FALSE
    ),
    error = function(e) {
      stop(sprintf("Failed to read %s: %s", path, e$message), call. = FALSE)
    }
  )

  if (!identical(names(df)[1], col_name_expected)) {
    stop(
      sprintf(
        "Unexpected column name in %s. Expected '%s', got '%s'.",
        path, col_name_expected, names(df)[1]
      ),
      call. = FALSE
    )
  }

  if (nrow(df) < 1) {
    stop(sprintf("Input file %s must contain at least one data row.", path), call. = FALSE)
  }

  val <- df[[1]][1]

  if (type == "character") {
    val <- as.character(val)
  } else if (type == "logical") {
    # Robust logical parsing
    if (is.numeric(val)) {
      val <- val != 0
    } else {
      vchar <- tolower(trimws(as.character(val)))
      if (vchar %in% c("true", "t", "yes", "y", "1")) {
        val <- TRUE
      } else if (vchar %in% c("false", "f", "no", "n", "0")) {
        val <- FALSE
      } else {
        stop(
          sprintf(
            "Unable to reliably parse logical from value '%s' in %s.",
            as.character(val), path
          ),
          call. = FALSE
        )
      }
    }
  }

  list(
    value = val,
    full_data = df
  )
}

