# Safe reader with validation
read_time_imputation <- function(path) {
  if (!file.exists(path)) {
    stop("Input file does not exist: ", path)
  }
  df <- tryCatch(
    read.delim(path, header = TRUE, sep = "\t", stringsAsFactors = FALSE, check.names = FALSE),
    error = function(e) stop("Failed to read input file: ", conditionMessage(e))
  )
  if (!"time_imputation" %in% names(df)) {
    stop("Input file must contain a 'time_imputation' column.")
  }
  if (nrow(df) == 0L) {
    stop("Input file has zero rows.")
  }
  df
}

ti_df <- read_time_imputation(in_file)

# Validate time_imputation values
valid_time_imputation <- function(x) {
  x <- trimws(x)
  # Allowed special values
  special <- c("first", "last")
  is_special <- x %in% special

  # HH:MM:SS pattern
  time_pattern <- "^\\d{2}:\\d{2}:\\d{2}$"
  is_time <- grepl(time_pattern, x)

  if (!all(is_special | is_time)) {
    bad <- unique(x[!(is_special | is_time)])
    stop(
      "Invalid time_imputation values detected: ",
      paste(bad, collapse = ", "),
      ". Allowed: 'first', 'last', or 'HH:MM:SS'."
    )
  }
  x
}

ti_df$time_imputation <- valid_time_imputation(ti_df$time_imputation)

# Apply admiral::get_imputation_target_time row-wise
get_target_safe <- function(ti) {
  tryCatch(
    admiral::get_imputation_target_time(time_imputation = ti),
    error = function(e) {
      stop("get_imputation_target_time failed for time_imputation='",
           ti, "': ", conditionMessage(e))
    }
  )
}

targets_list <- lapply(ti_df$time_imputation, get_target_safe)

# Convert list of lists to data frame
targets_df <- do.call(
  rbind,
  lapply(targets_list, function(x) {
    # Expecting list elements named "hour", "minute", "second"
    if (!all(c("hour", "minute", "second") %in% names(x))) {
      stop("get_imputation_target_time returned unexpected structure: ",
           paste(names(x), collapse = ", "))
    }
    data.frame(
      hour   = paste(x$hour,   collapse = ","),
      minute = paste(x$minute, collapse = ","),
      second = paste(x$second, collapse = ","),
      stringsAsFactors = FALSE
    )
  })
)

result_df <- cbind(ti_df, targets_df)

# Basic sanity checks for unexpected patterns
check_result <- function(df) {
  if (any(nchar(df$hour)   != 2L | !grepl("^\\d{2}$", df$hour))) {
    warning("Unexpected hour values detected.")
  }
  if (any(nchar(df$minute) != 2L | !grepl("^\\d{2}$", df$minute))) {
    warning("Unexpected minute values detected.")
  }
  if (any(nchar(df$second) != 2L | !grepl("^\\d{2}$", df$second))) {
    warning("Unexpected second values detected.")
  }
  if (any(is.na(df$hour) | is.na(df$minute) | is.na(df$second))) {
    warning("Missing values detected in imputation targets.")
  }
}

check_result(result_df)

# Write outputs
csv_path <- file.path(out_dir, "time_imputation_targets.csv")
rds_path <- file.path(out_dir, "time_imputation_targets.rds")

write.csv(result_df, csv_path, row.names = FALSE)
saveRDS(targets_list, rds_path)

# Confirm that files were written and re-readable
confirm_written <- function(path, type = c("csv", "rds")) {
  type <- match.arg(type)
  if (!file.exists(path)) {
    stop("Expected output file not found: ", path)
  }
  obj <- tryCatch(
    {
      if (type == "csv") {
        read.csv(path, stringsAsFactors = FALSE, check.names = FALSE)
      } else {
        readRDS(path)
      }
    },
    error = function(e) stop("Failed to re-read output file ", path, ": ", conditionMessage(e))
  )
  invisible(obj)
}

csv_check <- confirm_written(csv_path, "csv")
rds_check <- confirm_written(rds_path, "rds")

# Additional structural validation to catch data misalignment/parsing issues
if (!all(c("time_imputation", "hour", "minute", "second") %in% names(csv_check))) {
  warning("CSV output does not contain expected columns.")
}
if (!is.list(rds_check) || length(rds_check) != nrow(ti_df)) {
  warning("RDS output structure does not match input row count.")
}
