# imputed_dtc: imputed --DTC date (as character)
# For this example, assume imputed_dtc is the same as dtc, but in real workflows
# imputed_dtc would typically be a fully imputed date/time derived from dtc.

dat <- imputed_raw %>%
  mutate(
    imputed_dtc = dtc
  )

# Construct example min_dates and max_dates to demonstrate restriction.
# In real use, these would come from external reference data (e.g., treatment windows).
# Here we use simple, fixed boundaries broad enough to overlap with all test dates.
min_dates <- as.Date(c("2019-01-01", "2020-01-01", "2021-01-01"))
max_dates <- as.Date(c("2019-12-31", "2020-12-31", "2022-12-31"))

