#   dtc          partial --DTC (character)
#   imputed_dtc  imputed --DTC (character)
#   min_dates    vector of Date
#   max_dates    vector of Date
#
# It returns a Date; we convert it to character for writing.

safe_restrict <- purrr::safely(admiral::restrict_imputed_dtc_dt)

dat_res <- dat %>%
  mutate(
    restricted_dt = map_chr(
      dtc,
      ~ {
        res <- safe_restrict(
          dtc = .x,
          imputed_dtc = .x,
          min_dates = min_dates,
          max_dates = max_dates
        )
        if (!is.null(res$error)) {
          warning("restrict_imputed_dtc_dt error for dtc='", .x, "': ", res$error$message)
          return(NA_character_)
        }
        if (is.null(res$result)) {
