parse_partial_dt <- function(x) {
  # Trim whitespace
  x <- trimws(x)

  # Initialize components
  y   <- rep(NA_integer_, length(x))
  m   <- rep(NA_integer_, length(x))
  d   <- rep(NA_integer_, length(x))
  hh  <- rep(NA_integer_, length(x))
  mi  <- rep(NA_integer_, length(x))
  ss  <- rep(NA_integer_, length(x))

