  # then splits date by "-" and time by ":".

  for (i in seq_along(x)) {
    val <- x[i]
    if (val == "" || is.na(val)) next

    parts <- strsplit(val, "T", fixed = TRUE)[[1]]

    # Date part
    date_part <- parts[1]
    time_part <- if (length(parts) > 1) parts[2] else NA_character_

    # Date part: could be "YYYY", "YYYY-MM", "YYYY-MM-DD", or "---"
    if (!is.na(date_part) && date_part != "") {
      dp <- unlist(strsplit(date_part, "-", fixed = TRUE))

      # Handle leading dashes for pure time ("---")
      # e.g., "---" or "---T08:00:00"
      if (all(dp == "")) {
        # pure time – leave y/m/d as NA
