        }
        if (length(dp) >= 3 && nzchar(dp[3])) {
          d[i] <- suppressWarnings(as.integer(dp[3]))
        }
      }
    }

    # Time part: "hh:mm:ss" or "" / NA
    if (!is.na(time_part) && time_part != "") {
      tp <- unlist(strsplit(time_part, ":", fixed = TRUE))
      if (length(tp) >= 1 && nzchar(tp[1])) {
        hh[i] <- suppressWarnings(as.integer(tp[1]))
      }
      if (length(tp) >= 2 && nzchar(tp[2])) {
