      }
      if (length(tp) >= 3 && nzchar(tp[3])) {
        ss[i] <- suppressWarnings(as.integer(tp[3]))
      }
    }
  }

  list(
    y   = y,
    m   = m,
    d   = d,
    h   = hh,
    mi  = mi,
    s   = ss
  )
