library(admiralci)

#---------------------------
# Helper functions
#---------------------------

safe_read_tsv <- function(path) {
  if (!file.exists(path)) {
    stop(sprintf("Input file not found: %s", path))
  }
  df <- tryCatch(
    read.delim(path, header = TRUE, sep = "\t", quote = "", stringsAsFactors = FALSE),
    error = function(e) stop(sprintf("Failed to read %s: %s", path, e$message))
  )
  if (!is.data.frame(df) || nrow(df) == 0L || ncol(df) == 0L) {
    stop("Input file read but is empty or not a valid data frame.")
  }
  df
}

validate_hw_data <- function(df) {
  required_cols <- c("hw")
  missing <- setdiff(required_cols, names(df))
  if (length(missing) > 0L) {
    stop(sprintf("Missing required columns in input: %s", paste(missing, collapse = ", ")))
  }

  # Normalize to logical if possible
  if (is.logical(df$hw)) {
    return(df)
  }

  # Accept common encodings of TRUE/FALSE
  hw_char <- toupper(trimws(as.character(df$hw)))
  valid_vals <- c("TRUE", "FALSE", "T", "F", "1", "0", "Y", "N", "YES", "NO")
  if (any(!hw_char %in% valid_vals)) {
    bad <- unique(hw_char[!hw_char %in% valid_vals])
    stop(sprintf(
      "Invalid values in 'hw' column: %s. Expected logical-like values.",
      paste(bad, collapse = ", ")
    ))
  }

  hw_logical <- hw_char %in% c("TRUE", "T", "1", "Y", "YES")
  df$hw <- hw_logical
  df
}

assert_output_written <- function(path) {
  if (!file.exists(path)) {
    stop(sprintf("Expected output file was not written: %s", path))
  }
  info <- file.info(path)
  if (is.na(info$size) || info$size == 0L) {
    stop(sprintf("Output file appears to be empty or invalid: %s", path))
  }
}

check_for_unexpected_patterns <- function(obj) {
  if (is.data.frame(obj)) {
    # Basic structural checks
    if (any(duplicated(names(obj)))) {
      warning("Data frame has duplicated column names, which may indicate misalignment.")
    }
    if (any(sapply(obj, function(x) all(is.na(x))))) {
      warning("Data frame contains columns with all NA values; check for parsing issues.")
    }
  }
}

#---------------------------
# Main processing
#---------------------------

# Say hello admiral (message)
cat("hello admiral\n")

input_path  <- file.path("inputs", "hw.tsv")
output_dir  <- "outputs"

if (!dir.exists(output_dir)) {
  dir.create(output_dir, recursive = TRUE)
}

# Read and validate input
hw_raw <- safe_read_tsv(input_path)
hw_df  <- validate_hw_data(hw_raw)

# Call admiralci's hello_admiral for each row
results_list <- lapply(seq_len(nrow(hw_df)), function(i) {
  this_hw <- hw_df$hw[i]
  tryCatch(
    admiralci::hello_admiral(hw = this_hw),
    error = function(e) {
      stop(sprintf("hello_admiral failed for row %d (hw = %s): %s",
                   i, as.character(this_hw), e$message))
    }
  )
})

# Derive combined result
# If hello_admiral returns simple vectors / scalars, coerce to data frame
# If it returns data frames, bind them; otherwise keep as list
if (all(vapply(results_list, is.data.frame, logical(1)))) {
  happy_message <- do.call(rbind, results_list)
} else if (all(vapply(results_list, function(x) length(x) == 1L && !is.list(x), logical(1)))) {
  happy_message <- data.frame(
    row_id = seq_along(results_list),
    hw     = hw_df$hw,
    message = unlist(results_list),
    stringsAsFactors = FALSE
  )
} else {
  happy_message <- results_list
}

# Check for unexpected patterns or errors
check_for_unexpected_patterns(happy_message)

#---------------------------
# Save outputs
#---------------------------

if (is.data.frame(happy_message)) {
  out_csv <- file.path(output_dir, "happy_message.csv")
  write.csv(happy_message, out_csv, row.names = FALSE)
  assert_output_written(out_csv)
} else {
  out_rds <- file.path(output_dir, "happy_message.rds")
  saveRDS(happy_message, out_rds)
  assert_output_written(out_rds)
}

# Final confirmation
cat("Output successfully written to 'outputs/' and basic integrity checks passed.\n")
