    stop(sprintf("Input file not found: %s", path))
  }

  df <- tryCatch(
    {
      read.delim(
        file = path,
        header = TRUE,
        sep = "\t",
        stringsAsFactors = FALSE,
        check.names = FALSE
      )
    },
    error = function(e) {
      stop(sprintf("Failed to read %s: %s", path, e$message))
    }
  )

  # Basic validation
  if (!is.data.frame(df) || nrow(df) < 1L) {
    stop(sprintf("Input file %s is empty or not a valid data frame.", path))
  }

  if (!identical(colnames(df)[1], colname_expected)) {
    stop(
      sprintf(
        "Unexpected first column name in %s: got '%s', expected '%s'",
        path, colnames(df)[1], colname_expected
      )
    )
  }

  df
}

