# Read and validate inputs
#-----------------------------
subject_keys_df <- read_tsv_safe("inputs/subject_keys.tsv", "subject_keys")
signif_digits_df <- read_tsv_safe("inputs/signif_digits.tsv", "signif_digits")
save_memory_df   <- read_tsv_safe("inputs/save_memory.tsv", "save_memory")

# Subject keys: use all non-NA/non-empty values from first column (excluding header)
subject_keys_vec <- unique(trimws(subject_keys_df[[1]]))
subject_keys_vec <- subject_keys_vec[nzchar(subject_keys_vec)]

if (length(subject_keys_vec) < 1L) {
  stop("No valid subject key variables found in inputs/subject_keys.tsv")
}

# Build expression like exprs(STUDYID, USUBJID, ...)
subject_keys_expr <- rlang::expr(exprs(!!!rlang::syms(subject_keys_vec)))

# Significant digits: take first non-header entry and coerce to integer
signif_digits_vals <- unique(trimws(signif_digits_df[[1]]))
signif_digits_vals <- signif_digits_vals[nzchar(signif_digits_vals)]
signif_digits_vals <- signif_digits_vals[signif_digits_vals != "signif_digits"]

if (length(signif_digits_vals) < 1L) {
  stop("No valid signif_digits value found in inputs/signif_digits.tsv")
}

signif_digits_num <- suppressWarnings(as.integer(signif_digits_vals[1]))

if (is.na(signif_digits_num) || signif_digits_num <= 0L) {
  stop(
    sprintf(
      "Invalid signif_digits value '%s' in inputs/signif_digits.tsv; must be a positive integer.",
      signif_digits_vals[1]
    )
  )
}

# Save memory: interpret as logical; accept TRUE/FALSE/1/0/yes/no (case-insensitive)
save_memory_vals <- unique(trimws(save_memory_df[[1]]))
save_memory_vals <- save_memory_vals[nzchar(save_memory_vals)]
save_memory_vals <- save_memory_vals[save_memory_vals != "save_memory"]

if (length(save_memory_vals) < 1L) {
  stop("No valid save_memory value found in inputs/save_memory.tsv")
}

parse_logical <- function(x) {
  x_low <- tolower(x)
  if (x_low %in% c("true", "t", "1", "yes", "y"))  return(TRUE)
  if (x_low %in% c("false", "f", "0", "no", "n")) return(FALSE)
  NA
}

save_memory_logical <- parse_logical(save_memory_vals[1])

if (is.na(save_memory_logical)) {
  stop(
    sprintf(
      "Invalid save_memory value '%s' in inputs/save_memory.tsv; must be TRUE/FALSE-like.",
      save_memory_vals[1]
    )
  )
}

#-----------------------------
# Set admiral options
#-----------------------------
# This call has side effects; no return value is expected.
# subject_keys is supplied as expression (exprs(...)).
eval(
  rlang::expr(
    set_admiral_options(
      subject_keys = !!subject_keys_expr,
      signif_digits = !!signif_digits_num,
      save_memory   = !!save_memory_logical
    )
  )
)

#-----------------------------
# Capture and persist options
#-----------------------------
current_opts <- list(
  subject_keys   = get_admiral_option("subject_keys"),
  signif_digits  = get_admiral_option("signif_digits"),
  save_memory    = get_admiral_option("save_memory")
)

# For subject_keys (an expression/list of symbols), convert to character for CSV
subject_keys_chr <- vapply(
  rlang::get_expr(current_opts$subject_keys),
  function(sym) as.character(sym),
  character(1)
)

opts_df <- data.frame(
  option        = c("subject_keys", "signif_digits", "save_memory"),
  value_string  = c(
    paste(subject_keys_chr, collapse = ","),
    as.character(current_opts$signif_digits),
    as.character(current_opts$save_memory)
  ),
  stringsAsFactors = FALSE
)

# Write CSV (data frame) and RDS (full object list)
