rds_path <- "outputs/admiral_options.rds"

tryCatch(
  {
    write.csv(opts_df, file = csv_path, row.names = FALSE)
  },
  error = function(e) {
    stop(sprintf("Failed to write CSV output %s: %s", csv_path, e$message))
  }
)

tryCatch(
  {
    saveRDS(current_opts, file = rds_path)
  },
  error = function(e) {
    stop(sprintf("Failed to write RDS output %s: %s", rds_path, e$message))
  }
