  {
    readRDS(rds_path)
  },
  error = function(e) {
    stop(sprintf("Failed to re-read RDS output %s: %s", rds_path, e$message))
  }
)

# Sanity checks on RDS structure
if (!is.list(opts_rds_check) ||
