library(admiraldev)

#---- Helper functions ----

stop_if_not_file <- function(path) {
  if (!file.exists(path)) {
    stop(sprintf("Input file not found: %s", path), call. = FALSE)
  }
}

validate_character_vector <- function(x, nm = "x") {
  if (!is.vector(x) || is.list(x)) {
    stop(sprintf("`%s` must be an atomic vector.", nm), call. = FALSE)
  }
  if (!is.character(x)) {
    stop(sprintf("`%s` must be a character vector. Actual type: %s",
                 nm, paste(class(x), collapse = "/")),
         call. = FALSE)
  }
  invisible(x)
}

check_output_written <- function(path) {
  if (!file.exists(path)) {
    stop(sprintf("Expected output file not found after writing: %s", path),
         call. = FALSE)
  }
  info <- file.info(path)
  if (is.na(info$size) || info$size == 0) {
    stop(sprintf("Output file exists but is empty: %s", path), call. = FALSE)
  }
  invisible(TRUE)
}

check_unexpected_patterns <- function(x, nm = "x") {
  if (anyNA(x)) {
    warning(sprintf("Detected NA values in `%s`.", nm), call. = FALSE)
  }
  if (any(x == "", na.rm = TRUE)) {
    warning(sprintf("Detected empty strings in `%s`.", nm), call. = FALSE)
  }
  # Look for suspicious whitespace patterns
  if (any(grepl("^\\s|\\s$", x))) {
    warning(sprintf("Detected leading/trailing whitespace in `%s`.", nm),
            call. = FALSE)
  }
  # Look for repeated backquotes that might indicate double-wrapping
  if (any(grepl("``|''", x))) {
    warning(sprintf("Detected repeated backquotes in `%s`.", nm),
            call. = FALSE)
  }
  invisible(TRUE)
}

#---- Read and validate input ----

