x_backquoted <- tryCatch(
  {
    backquote(x = x_vec)
  },
  error = function(e) {
    stop(sprintf("Error while applying `backquote()` to `x`: %s", e$message),
         call. = FALSE)
  }
)

validate_character_vector(x_backquoted, "x_backquoted")
check_unexpected_patterns(x_backquoted, "x_backquoted")

