library(admiraldev)

# ---- Helper functions ----

stop_if_not_file <- function(path) {
  if (!file.exists(path)) {
    stop(sprintf("Input file does not exist: %s", path))
  }
}

validate_vector <- function(x, name = "x") {
  if (!is.atomic(x)) {
    stop(sprintf("Input '%s' must be an atomic vector, got class: %s",
                 name, paste(class(x), collapse = ", ")))
  }
  if (length(x) == 0L) {
    warning(sprintf("Input '%s' is an empty vector.", name))
  }
  invisible(TRUE)
}

write_and_check <- function(obj, path, type = c("csv", "rds")) {
  type <- match.arg(type)

  dir.create(dirname(path), showWarnings = FALSE, recursive = TRUE)

  if (type == "csv") {
    df <- as.data.frame(obj, stringsAsFactors = FALSE)
    write.csv(df, file = path, row.names = FALSE)
  } else if (type == "rds") {
    saveRDS(obj, file = path)
  }

  if (!file.exists(path)) {
    stop(sprintf("Output file not written: %s", path))
  }

  if (type == "csv") {
    chk <- try(read.csv(path, stringsAsFactors = FALSE), silent = TRUE)
  } else {
    chk <- try(readRDS(path), silent = TRUE)
  }

  if (inherits(chk, "try-error")) {
    stop(sprintf("Error re-reading output file (possible corruption): %s", path))
  }

