# Helper: safe read of TSV
safe_read_tsv <- function(path) {
  if (!file.exists(path)) {
    stop(sprintf("Input file not found: %s", path))
  }
  dat <- tryCatch(
    read.delim(path, stringsAsFactors = FALSE, check.names = FALSE),
    error = function(e) stop("Failed to read TSV: ", conditionMessage(e))
  )
  if (ncol(dat) == 0L) stop("Input file has no columns.")
  dat
}

# Helper: determine if object is a data.frame-like
is_df_like <- function(x) {
  is.data.frame(x) || is.matrix(x) || inherits(x, "tbl_df")
}

# Input
in_path <- "inputs/arg.tsv"
arg_raw <- safe_read_tsv(in_path)

# Basic validation
if (!"arg" %in% names(arg_raw)) {
  stop("Input file must contain a column named 'arg'.")
}

# Extract the value(s) from the 'arg' column
arg_vals <- arg_raw[["arg"]]

# Try to interpret `arg` as expression(s) using exprs()/desc() style
# e.g. it may contain strings like "exprs(USUBJID, desc(ADT))"
# If parsing fails, we pass the raw object to is_order_vars directly.
arg_obj <- NULL
parse_error <- NULL

if (length(arg_vals) == 1L && is.character(arg_vals)) {
  txt <- trimws(arg_vals[1])
  # Ensure it looks like an expression call before eval
  if (grepl("exprs\\(", txt) || grepl("desc\\(", txt)) {
    # evaluate in a controlled environment
    env <- new.env(parent = emptyenv())
    # Attach desc/exprs from admiraldev
    env$exprs <- admiraldev::exprs
