  stop("Input TSV contains no rows.")
}

# Extract code as a single character string
code_vec <- code_tbl$code

# Handle potential multi-line code in single or multiple rows
code_chr <- paste(code_vec, collapse = "\n")

if (!is.character(code_chr) || length(code_chr) != 1L || nchar(code_chr) == 0L) {
  stop("Parsed code content is invalid or empty.")
}

# Parse code using admiraldev::parse_code
parsed <- tryCatch(
  admiraldev::parse_code(code = code_chr),
  error = function(e) {
    stop("parse_code failed: ", conditionMessage(e))
  }
)

# Validate parsed object structure
if (!is.list(parsed) || length(parsed) == 0L) {
  stop("parse_code returned an empty or non-list object.")
}

# Check each element has required components
required_fields <- c("expr", "srcref", "eval")

bad_idx <- vapply(
  parsed,
  function(x) {
    if (!is.list(x)) return(TRUE)
    !all(required_fields %in% names(x))
  },
  logical(1)
)

