  error = function(e) {
    stop("Failed to reload RDS output: ", conditionMessage(e))
  }
)

if (!identical(length(parsed_reload), length(parsed))) {
  stop("Mismatch in length between original and reloaded parsed object.")
}

summary_reload <- tryCatch(
  read.csv(parsed_csv_path, stringsAsFactors = FALSE, check.names = FALSE),
  error = function(e) {
    stop("Failed to reload CSV output: ", conditionMessage(e))
