write_object_safely <- function(obj, base_name) {
  if (is.null(obj)) {
    warning(sprintf("Object '%s' is NULL. Saving as RDS only.", base_name))
    out_rds <- file.path("outputs", paste0(base_name, ".rds"))
    saveRDS(obj, out_rds)
