  out_files <- list(rds = NULL, csv = NULL)

  # Always save RDS
  out_rds <- file.path("outputs", paste0(base_name, ".rds"))
  saveRDS(obj, out_rds)
  out_files$rds <- out_rds

  # Save CSV if data-frame-like and valid
  if (is_df_like) {
    # Basic validation
    if (nrow(obj) > 0 && ncol(obj) > 0) {
      out_csv <- file.path("outputs", paste0(base_name, ".csv"))
