#--------------------------------------------------------------------
p <- tryCatch(
  {
    ggsurvfit(fit) +
      scale_ggsurvfit(
        x_scales = x_scales,
        y_scales = y_scales
      )
  },
  error = function(e) stop("Failed to build survival plot: ", e$message)
)

