  }
  if (!"x" %in% names(df)) {
    stop("Log definition table must contain a column named 'x'.")
  }
  if (anyNA(df$x)) {
    stop("Column 'x' in log definition table contains NA values.")
  }
  if (any(df$x == "")) {
    warning("Column 'x' in log definition contains empty strings.")
  }
  df
}

# Main execution wrapped in error handler
main <- function() {
  # Read input
  log_def_path <- file.path("inputs", "logrx.tsv")
  if (!file.exists(log_def_path)) {
    stop(sprintf("Input file '%s' does not exist.", log_def_path))
  }

