        {
          readRDS(out_path)
        },
        error = function(e) {
          stop(sprintf("Failed to reread RDS '%s': %s", out_path, conditionMessage(e)))
        }
      )

      if (is.null(reread)) {
        warning(sprintf("Reread object from '%s' is NULL; potential write/read issue.", out_path))
      }
    }
  }

  # Also store the original log definition used for initialization
  safe_write_csv(log_def, file.path("outputs", "log_definition.csv"))

  invisible(NULL)
}

tryCatch(
  main(),
  error = function(e) {
    message("Fatal error during logrx initialization: ", conditionMessage(e))
    quit(status = 1)
  }
)
