  v <- x[!is.na(x)]
  if (length(v) == 0L) {
    stop("No non-NA values found in ", label, ".")
  }
  if (length(unique(v)) > 1L) {
    warning(
      "Multiple distinct values found in ", label,
      "; using the first non-NA value: ", v[1]
    )
  }
  v[1]
}

file_val     <- get_first_non_na(file_df$file,         "file")
log_name_val <- get_first_non_na(log_name_df$log_name, "log_name")
log_path_val <- get_first_non_na(log_path_df$log_path, "log_path")

# extra_info: make a named list, checking duplicates
extra_info_vec <- extra_info_df$x[!is.na(extra_info_df$x)]
if (length(extra_info_vec) == 0L) {
  warning("extra_info.tsv contains no non-NA values; extra_info will be NULL.")
  extra_info_list <- NULL
} else {
  dup_vals <- extra_info_vec[duplicated(extra_info_vec)]
  if (length(dup_vals) > 0L) {
    warning(
      "Duplicate entries found in extra_info: ",
      paste(unique(dup_vals), collapse = ", "),
      ". Using unique values only."
    )
