# Use first non-NA value from each
get_first_non_na <- function(x, label) {
  v <- x[!is.na(x)]
  if (length(v) == 0L) {
    stop("No non-NA values found in ", label, ".")
  }
  if (length(unique(v)) > 1L) {
    warning(
      "Multiple distinct values found in ", label,
      "; using the first non-NA value: ", v[1]
    )
  }
  v[1]
}

