      paste(unique(dup_vals), collapse = ", "),
      ". Using unique values only."
    )
  }
  extra_info_vec <- unique(extra_info_vec)
  # named list with names = values, contents = NA (or the same string)
  extra_info_list <- as.list(extra_info_vec)
  names(extra_info_list) <- extra_info_vec
}

