##-------------------------------

# Function to check a written file exists and is non-empty
check_written_file <- function(path) {
  if (!file.exists(path)) {
    stop("Expected output file not found: ", path)
  }
  info <- file.info(path)
  if (is.na(info$size) || info$size <= 0) {
    stop("Output file appears empty or unreadable: ", path)
  }
  invisible(TRUE)
}

# Check outputs
walk(
  c(params_path, extra_info_path, state_path),
  check_written_file
)

# Re-read CSV and perform a basic sanity check for parsing/misalignment
params_check <- tryCatch(
  readr::read_csv(params_path, show_col_types = FALSE),
  error = function(e) {
    stop("Failed to re-read params CSV: ", conditionMessage(e))
  }
)

if (!all(c("param", "value") %in% names(params_check))) {
  stop("Unexpected column structure in params CSV; possible misalignment.")
}

if (any(is.na(params_check$param)) || any(params_check$param == "")) {
  warning("Detected empty or NA 'param' entries in params CSV; check input alignment.")
}

if (any(is.na(params_check$value)) || any(params_check$value == "")) {
  warning("Detected empty or NA 'value' entries in params CSV; check input alignment.")
}

