  }
  df <- tryCatch(
    read.delim(path, header = TRUE, sep = "\t", stringsAsFactors = FALSE),
    error = function(e) stop(sprintf("Error reading %s: %s", path, e$message))
  )
  if (!is.data.frame(df) || ncol(df) != 1L) {
    stop(sprintf("File %s must contain exactly one column.", path))
  }
  if (!identical(names(df)[1], colname_expected)) {
    stop(sprintf("File %s must have column named '%s', found '%s'.",
                 path, colname_expected, names(df)[1]))
  }
  df[[1]]
}

