      df_check <- tryCatch(
        utils::read.csv(csv_path, stringsAsFactors = FALSE),
        error = function(e) e
      )
      if (inherits(df_check, "error")) {
        stop("Error reading back CSV: ", conditionMessage(df_check))
      }
      # Check for obvious misalignment: column count match
      if (!identical(ncol(df_check), ncol(obj))) {
        stop("Column count mismatch between written and read-back CSV.")
      }
    } else {
      # For non-data.frame objects (e.g., character vector from sbj_vars)
      # Write as simple CSV with one column
      df_tmp <- data.frame(value = obj, stringsAsFactors = FALSE)
