fail <- function(msg) {
  message("ERROR: ", msg)
  quit(status = 1, save = "no")
}

## Paths
in_file  <- "inputs/x.tsv"
out_file <- "outputs/x_anycase_regexps.csv"

## Validate input file existence
if (!file.exists(in_file)) {
  fail(paste0("Input file not found: ", in_file))
}

