  {
    check_is_nested_rowvar(arg = arg_vec)
  },
  error = function(e) {
    stop("check_is_nested_rowvar failed: ", conditionMessage(e))
  }
)

# Determine object type and save appropriately
out_base <- file.path("outputs", "check_is_nested_rowvar_result")

if (is.data.frame(check_result)) {
  out_file <- paste0(out_base, ".csv")
  tryCatch(
    {
      write.csv(check_result, out_file, row.names = FALSE)
    },
    error = function(e) {
      stop("Failed to write CSV output: ", conditionMessage(e))
    }
  )
} else {
  out_file <- paste0(out_base, ".rds")
  tryCatch(
    {
      saveRDS(check_result, out_file)
    },
    error = function(e) {
      stop("Failed to write RDS output: ", conditionMessage(e))
    }
  )
}

# Confirm that file was written
if (!file.exists(out_file)) {
  stop("Output file was not created as expected: ", out_file)
}

# Reload and sanity-check for unexpected patterns or parsing issues
reloaded <- tryCatch(
  {
    if (grepl("\\.csv$", out_file)) {
      read.csv(out_file, stringsAsFactors = FALSE, check.names = FALSE)
    } else {
      readRDS(out_file)
    }
  },
  error = function(e) {
    stop("Failed to reload output file: ", conditionMessage(e))
  }
)

# Basic consistency checks
if (is.logical(check_result) && length(check_result) == 1) {
  if (!identical(check_result, reloaded)) {
    stop("Reloaded logical value does not match original result.")
  }
} else if (is.data.frame(check_result)) {
  if (!identical(dim(check_result), dim(reloaded))) {
    stop("Reloaded data frame dimensions differ from original.")
  }
} else {
  # For other object types, do a simple class and structure check
  if (!identical(class(check_result), class(reloaded))) {
    stop("Reloaded object class differs from original.")
  }
}

# Optional: simple pattern checks that might indicate misalignment in string data frames
if (is.data.frame(reloaded)) {
  char_cols <- vapply(reloaded, is.character, logical(1))
  if (any(char_cols)) {
    suspicious <- lapply(reloaded[char_cols], function(col) {
      grep("^[\\s,;]+$|,,|;;", col, perl = TRUE, value = TRUE)
    })
    if (any(vapply(suspicious, length, integer(1)) > 0)) {
      warning("Potentially suspicious string patterns detected in reloaded data (possible misalignment).")
    }
  }
}
