library(tidytlg)

# Helper: safe read TSV with validation
read_single_numeric <- function(path, colname) {
  if (!file.exists(path)) {
    stop(sprintf("Input file not found: %s", path))
  }
  df <- tryCatch(
    read.delim(path, stringsAsFactors = FALSE, check.names = FALSE),
    error = function(e) stop(sprintf("Failed to read %s: %s", path, e$message))
  )

  if (!colname %in% names(df)) {
    stop(sprintf("Expected column '%s' not found in %s", colname, path))
  }
  if (nrow(df) != 1L) {
    stop(sprintf("Expected exactly 1 row in %s, found %d", path, nrow(df)))
  }

  val <- df[[colname]][1]
  if (is.factor(val)) val <- as.character(val)
  if (!suppressWarnings(!is.na(as.numeric(val)))) {
    stop(sprintf("Value in %s[%s] is not numeric: '%s'", path, colname, as.character(val)))
  }
  as.numeric(val)
}

# Read and validate inputs
col_file  <- file.path("inputs", "col.tsv")
rows_file <- file.path("inputs", "rows.tsv")

col_val  <- read_single_numeric(col_file,  "col")
rows_val <- read_single_numeric(rows_file, "rows")

if (col_val <= 0 || col_val != as.integer(col_val)) {
  stop(sprintf("Column index must be positive integer, got %s", col_val))
}
if (rows_val <= 0 || rows_val != as.integer(rows_val)) {
  stop(sprintf("Row index must be positive integer, got %s", rows_val))
}

col_val  <- as.integer(col_val)
rows_val <- as.integer(rows_val)

# Create a minimal example table to apply borders to
# (In a real workflow, replace this with actual table object)
set.seed(123)
tbl_df <- data.frame(
  col1 = sample(letters, 50, replace = TRUE),
  col2 = sample(LETTERS, 50, replace = TRUE),
  col3 = sample(1:100, 50, replace = TRUE),
  stringsAsFactors = FALSE
)

n_cols <- ncol(tbl_df)
n_rows <- nrow(tbl_df)

if (col_val > n_cols) {
  stop(sprintf("Requested column %d exceeds available columns (%d)", col_val, n_cols))
}
if (rows_val > n_rows) {
  stop(sprintf("Requested row %d exceeds available rows (%d)", rows_val, n_rows))
}

# Construct rows range for col_borders
rows_range <- rows_val:n_rows

# Apply col_borders with error handling
bordered_obj <- tryCatch(
  col_borders(
    x    = tbl_df,
    col  = col_val,
    rows = rows_range
  ),
  error = function(e) {
    stop(sprintf("col_borders failed: %s", e$message))
  }
)

# Prepare outputs directory
out_dir <- "outputs"
