  write.csv(bordered_obj, table_path, row.names = FALSE)
} else if (is.list(bordered_obj) && !is.null(bordered_obj$data) && inherits(bordered_obj$data, "data.frame")) {
  write.csv(bordered_obj$data, table_path, row.names = FALSE)
} else {
  # Fallback: try to coerce to data.frame; if fails, skip CSV
  df_out <- tryCatch(
    as.data.frame(bordered_obj),
    error = function(e) NULL
  )
  if (!is.null(df_out)) {
    write.csv(df_out, table_path, row.names = FALSE)
  }
}

# Always save full object as RDS
saveRDS(bordered_obj, object_path)

# Confirm files written
if (!file.exists(object_path)) {
  stop(sprintf("RDS output file was not created: %s", object_path))
}

if (!file.exists(table_path)) {
  warning(sprintf("CSV output file was not created (object may not be data-frame-like): %s", table_path))
