  )

  if (nrow(csv_df) == 0L) {
    warning("CSV output has 0 rows; check that col_borders returned meaningful data.")
  }
  if (anyNA(csv_df)) {
    warning("CSV output contains NA values; verify data alignment and parsing.")
  }
}
